import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";
import { getCorsHeaders } from "../_shared/cors.ts";
import { getClientIp } from "../_shared/clientIp.ts";
import { buildEdgeRateLimitKey } from "../_shared/rateLimitKey.ts";
import { verifyTurnstileToken } from "../_shared/turnstile.ts";
import { normalizeContactEmail } from "../_shared/contactValidation.ts";

function normalizeSource(value: unknown): string | null {
  if (typeof value !== "string") return null;
  const source = value.trim().slice(0, 50);
  if (!source || /[<>]/.test(source)) return null;
  return source;
}

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: getCorsHeaders(req) });
  }

  if (req.method !== "POST") {
    return new Response(
      JSON.stringify({ success: false, error: "Method not allowed" }),
      {
        headers: { ...getCorsHeaders(req), "Content-Type": "application/json", Allow: "POST, OPTIONS" },
        status: 405,
      }
    );
  }

  try {
    const clientIp = getClientIp(req);

    const supabaseUrl = Deno.env.get("SUPABASE_URL") ?? "";
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "";
    if (!supabaseUrl || !serviceRoleKey) {
      return new Response(
        JSON.stringify({ success: false, error: "Service unavailable" }),
        { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" }, status: 503 },
      );
    }

    const supabase = createClient(supabaseUrl, serviceRoleKey);

    const rateLimitKey = await buildEdgeRateLimitKey("edge-subscribe", req, clientIp);
    const { data: edgeRateLimitRows, error: edgeRateError } = await supabase.rpc("consume_rate_limit", {
      p_key: rateLimitKey,
      p_max_requests: 15,
      p_window_ms: 60000,
    });
    const edgeRateLimit = Array.isArray(edgeRateLimitRows) ? edgeRateLimitRows[0] : edgeRateLimitRows;
    if (edgeRateError || !edgeRateLimit?.allowed) {
      return new Response(
        JSON.stringify({
          success: false,
          error: "Too many attempts. Try again in a few minutes.",
        }),
        { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" }, status: 429 },
      );
    }

    const body = await req.json();
    const language = body?.language === 'en' ? 'en' : 'pl';
    const turnstile = await verifyTurnstileToken(body?.turnstile_token, clientIp);
    if (!turnstile.ok) {
      return new Response(
        JSON.stringify({
          success: false,
          error: language === "pl" ? "Weryfikacja CAPTCHA nie powiodła się." : "Captcha verification failed.",
        }),
        { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" }, status: 400 },
      );
    }

    const email = normalizeContactEmail(body?.email);
    const source = normalizeSource(body?.source);

    if (!email) {
      return new Response(
        JSON.stringify({ success: false, error: language === "pl" ? "Podaj poprawny adres email." : "Enter a valid email address." }),
        { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" }, status: 400 }
      );
    }

    const { data: id, error } = await supabase.rpc("safe_insert_newsletter_subscriber", {
      p_email: email,
      p_client_ip: clientIp,
      p_language: language,
      ...(source ? { p_source: source } : {}),
    });

    if (error) {
      const msg = error.message || "Unknown error";
      const isRateLimit = msg.toLowerCase().includes("rate limit");
      const isDuplicate = msg.includes("unique") || error.code === "23505";
      return new Response(
        JSON.stringify({
          success: false,
          error: isRateLimit
            ? language === "pl" ? "Zbyt wiele prób. Spróbuj ponownie za kilka minut." : "Too many attempts. Try again in a few minutes."
            : isDuplicate
              ? language === "pl" ? "Ten adres email jest już zapisany do newslettera." : "This email address is already on the list."
              : language === "pl" ? "Nie udało się zapisać adresu. Spróbuj ponownie później." : "Could not subscribe this address. Try again later.",
        }),
        {
          headers: { ...getCorsHeaders(req), "Content-Type": "application/json" },
          status: isRateLimit ? 429 : 400,
        }
      );
    }

    return new Response(
      JSON.stringify({ success: true, id }),
      { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" }, status: 200 }
    );
  } catch {
    console.error("subscribe-newsletter error");
    return new Response(
      JSON.stringify({
        success: false,
        error: "Nie udało się zapisać adresu. Spróbuj ponownie później.",
      }),
      {
        headers: { ...getCorsHeaders(req), "Content-Type": "application/json" },
        status: 500,
      }
    );
  }
});

const PRODUCTION_ORIGINS = [
  "https://vezvision.com",
  "https://www.vezvision.com",
] as const;

const LOCAL_ORIGINS = [
  "http://localhost:5174",
  "http://127.0.0.1:5174",
  "http://localhost:4173",
  "http://127.0.0.1:4173",
] as const;

function parseExtraOrigins(): string[] {
  const raw = Deno.env.get("ALLOWED_CORS_ORIGINS");
  if (!raw?.trim()) return [];

  return raw
    .split(",")
    .map((origin) => origin.trim())
    .filter((origin) => {
      if (!origin) return false;
      try {
        const url = new URL(origin);
        return url.protocol === "https:" || url.protocol === "http:";
      } catch {
        return false;
      }
    });
}

function getAllowedOrigins(): string[] {
  return [...PRODUCTION_ORIGINS, ...LOCAL_ORIGINS, ...parseExtraOrigins()];
}

export function getCorsHeaders(req: Request): Record<string, string> {
  const origin = req.headers.get("origin") ?? "";
  const allowedOrigins = getAllowedOrigins();
  const allowedOrigin = allowedOrigins.includes(origin) ? origin : PRODUCTION_ORIGINS[0];

  return {
    "Access-Control-Allow-Origin": allowedOrigin,
    "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Access-Control-Max-Age": "86400",
  };
}

/** Browser requests include Origin; curl/scripts typically do not. */
export function hasTrustedBrowserOrigin(req: Request): boolean {
  const origin = req.headers.get("origin");
  if (!origin) return false;
  return getAllowedOrigins().includes(origin);
}

/** Edge bundle — logic mirrored in shared/clientIp.ts for unit tests. */
const IP_PATTERN = /^[\d.a-fA-F:]+$/;

function isValidIp(value: string): boolean {
  const trimmed = value.trim();
  return trimmed.length > 0 && trimmed.length <= 45 && IP_PATTERN.test(trimmed);
}

export function getClientIpFromHeaders(headers: Pick<Headers, 'get'>): string {
  const trustedHeaders = ['cf-connecting-ip', 'true-client-ip'] as const;

  for (const header of trustedHeaders) {
    const value = headers.get(header);
    if (value && isValidIp(value)) {
      return value.trim().slice(0, 45);
    }
  }

  return 'unknown';
}

export function getClientIp(req: Request): string {
  return getClientIpFromHeaders(req.headers);
}

/** Edge bundle — logic mirrored in shared/rateLimitKey.ts */

export async function sha256Hex16(input: string): Promise<string> {
  const data = new TextEncoder().encode(input);
  const hash = await crypto.subtle.digest("SHA-256", data);
  return [...new Uint8Array(hash)]
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("")
    .slice(0, 16);
}

export async function buildEdgeRateLimitKey(
  scope: string,
  req: Pick<Request, "headers">,
  clientIp: string,
): Promise<string> {
  const userAgent = (req.headers.get("user-agent") ?? "unknown").slice(0, 120);
  const acceptLanguage = (req.headers.get("accept-language") ?? "").slice(0, 40);
  const fingerprint = await sha256Hex16(`${clientIp}|${userAgent}|${acceptLanguage}`);
  return `${scope}:${fingerprint}`;
}

interface TurnstileVerifyResponse {
  success?: boolean;
}

function isDeployedEdge(): boolean {
  return Boolean(Deno.env.get("DENO_DEPLOYMENT_ID")?.trim());
}

/** When TURNSTILE_SECRET_KEY is unset, verification is skipped in local dev only. */
export async function verifyTurnstileToken(
  token: unknown,
  remoteIp?: string,
): Promise<{ ok: true } | { ok: false; reason: string }> {
  const secret = Deno.env.get("TURNSTILE_SECRET_KEY");
  if (!secret?.trim()) {
    if (isDeployedEdge()) {
      return { ok: false, reason: "turnstile_not_configured" };
    }
    return { ok: true };
  }

  if (typeof token !== "string" || !token.trim()) {
    return { ok: false, reason: "missing_turnstile_token" };
  }

  try {
    const response = await fetch("https://challenges.cloudflare.com/turnstile/v0/siteverify", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        secret,
        response: token.trim(),
        ...(remoteIp ? { remoteip: remoteIp } : {}),
      }),
    });

    const data = (await response.json()) as TurnstileVerifyResponse;
    if (!response.ok || data.success !== true) {
      return { ok: false, reason: "turnstile_failed" };
    }

    return { ok: true };
  } catch {
    return { ok: false, reason: "turnstile_unreachable" };
  }
}

/** Edge bundle — logic mirrored in shared/contactValidation.ts (Zod). */
import { z } from "npm:zod@3.25.76";

export const CONTACT_EMAIL_PATTERN = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
export const CONTACT_PHONE_PATTERN = /^\+?[0-9()\s-]{5,30}$/;

const contactEmailSchema = z
  .string()
  .trim()
  .toLowerCase()
  .min(5)
  .max(254)
  .regex(CONTACT_EMAIL_PATTERN);

const contactPhoneSchema = z.string().trim().regex(CONTACT_PHONE_PATTERN);

function contactTextSchema(maxLength: number, minLength = 1) {
  return z.string().trim().min(minLength).max(maxLength);
}

export function normalizeContactText(
  value: unknown,
  maxLength: number,
  minLength = 1,
): string | null {
  const result = contactTextSchema(maxLength, minLength).safeParse(value);
  return result.success ? result.data : null;
}

export const normalizeText = normalizeContactText;

export function normalizeContactEmail(value: unknown): string | null {
  const result = contactEmailSchema.safeParse(value);
  return result.success ? result.data : null;
}

export function isContactPhoneProvided(value: unknown): boolean {
  if (value === null || value === undefined) return false;
  if (typeof value === "string") return value.trim().length > 0;
  return true;
}

export function normalizeContactPhone(value: unknown): { phone: string | null; invalid: boolean } {
  if (!isContactPhoneProvided(value)) {
    return { phone: null, invalid: false };
  }

  if (typeof value !== "string") {
    return { phone: null, invalid: true };
  }

  const result = contactPhoneSchema.safeParse(value);
  if (!result.success) {
    return { phone: null, invalid: true };
  }

  return { phone: result.data, invalid: false };
}
